import java.sql.*;

public class SecureSQLQuery {
    public static void main(String[] args) {
        String userInput = "admin'; DROP TABLE users;--"; // Malicious input

        try {
            String url = "jdbc:mysql://localhost:3306/mydatabase";
            String username = "root";
